import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const CourseCard = ({ course }) => {
  const navigate = useNavigate();
  const [downloading, setDownloading] = useState(false);
  const [downloadProgress, setDownloadProgress] = useState(0);

  const handleClick = () => {
    navigate(`/courses/${course.id}`);
  };

  const handleDownload = async (e) => {
    e.stopPropagation(); // Prevent card click
    
    if (!course.downloadUrl) {
      alert('No download available for this course');
      return;
    }

    setDownloading(true);
    setDownloadProgress(0);

    try {
      const response = await fetch(course.downloadUrl);
      
      if (!response.ok) {
        throw new Error('Download failed');
      }

      const contentLength = response.headers.get('content-length');
      const total = parseInt(contentLength, 10);
      let loaded = 0;

      const reader = response.body.getReader();
      const chunks = [];

      while (true) {
        const { done, value } = await reader.read();
        
        if (done) break;
        
        chunks.push(value);
        loaded += value.length;
        
        if (total) {
          const progress = Math.round((loaded / total) * 100);
          setDownloadProgress(progress);
        }
      }

      // Combine chunks
      const blob = new Blob(chunks);
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${course.name.replace(/\s+/g, '-').toLowerCase()}-materials.zip`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      // Update download count locally
      if (course.onDownload) {
        course.onDownload(course.id);
      }

      setTimeout(() => {
        setDownloading(false);
        setDownloadProgress(0);
      }, 1000);

    } catch (error) {
      console.error('Download error:', error);
      alert('Download failed. Please try again.');
      setDownloading(false);
      setDownloadProgress(0);
    }
  };

  const handleQuickView = (e) => {
    e.stopPropagation();
    // Show quick preview modal
    if (course.onPreview) {
      course.onPreview(course);
    } else {
      alert(`Preview: ${course.name}\nNotes: ${course.notes || 0}\nPYQs: ${course.pyqs || 0}`);
    }
  };

  const styles = {
    card: {
      background: 'white',
      borderRadius: '12px',
      padding: '1.5rem',
      boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
      textAlign: 'center',
      transition: 'all 0.3s ease',
      cursor: 'pointer',
      border: '1px solid #e5e7eb',
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'space-between',
      position: 'relative',
      overflow: 'hidden',
      '&:hover': {
        transform: 'translateY(-5px)',
        boxShadow: '0 10px 25px rgba(0, 0, 0, 0.15)'
      }
    },
    cardIcon: {
      fontSize: '2.5rem',
      marginBottom: '1rem',
      transition: 'transform 0.3s'
    },
    cardTitle: {
      fontSize: '1.25rem',
      fontWeight: '600',
      color: '#1f2937',
      marginBottom: '0.5rem',
      lineHeight: '1.4'
    },
    cardBranch: {
      color: '#6b7280',
      fontSize: '0.9rem',
      marginBottom: '1rem'
    },
    codeBadge: {
      position: 'absolute',
      top: '10px',
      right: '10px',
      background: '#dbeafe',
      color: '#1d4ed8',
      padding: '3px 8px',
      borderRadius: '12px',
      fontSize: '0.7rem',
      fontWeight: '500'
    },
    tagsContainer: {
      display: 'flex',
      justifyContent: 'center',
      gap: '0.5rem',
      marginBottom: '1rem',
      flexWrap: 'wrap'
    },
    tag: {
      background: '#e0e7ff',
      color: '#4f46e5',
      padding: '0.25rem 0.75rem',
      borderRadius: '12px',
      fontSize: '0.75rem',
      fontWeight: '500',
      transition: 'all 0.3s',
      '&:hover': {
        background: '#c7d2fe',
        transform: 'scale(1.05)'
      }
    },
    stats: {
      display: 'flex',
      justifyContent: 'space-between',
      marginTop: '1rem',
      fontSize: '0.8rem',
      color: '#6b7280',
      padding: '0.5rem',
      background: '#f9fafb',
      borderRadius: '8px'
    },
    statItem: {
      display: 'flex',
      alignItems: 'center',
      gap: '0.25rem'
    },
    actionButtons: {
      display: 'flex',
      gap: '0.5rem',
      marginTop: '1rem'
    },
    primaryButton: {
      flex: 2,
      padding: '0.75rem',
      background: 'linear-gradient(90deg, #4f46e5, #7c3aed)',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      fontWeight: '600',
      fontSize: '0.9rem',
      cursor: 'pointer',
      transition: 'all 0.3s',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '0.5rem',
      '&:hover': {
        background: 'linear-gradient(90deg, #4338ca, #6d28d9)',
        transform: 'translateY(-2px)'
      }
    },
    secondaryButton: {
      flex: 1,
      padding: '0.75rem',
      background: '#f3f4f6',
      color: '#4b5563',
      border: '1px solid #d1d5db',
      borderRadius: '8px',
      fontWeight: '500',
      fontSize: '0.9rem',
      cursor: 'pointer',
      transition: 'all 0.3s',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      '&:hover': {
        background: '#e5e7eb',
        transform: 'translateY(-2px)'
      }
    },
    downloadProgress: {
      position: 'absolute',
      bottom: 0,
      left: 0,
      right: 0,
      height: '4px',
      background: 'linear-gradient(90deg, #10b981, #34d399)',
      transition: 'width 0.3s',
      borderRadius: '0 0 12px 12px'
    },
    loadingOverlay: {
      position: 'absolute',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      background: 'rgba(255, 255, 255, 0.9)',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      borderRadius: '12px',
      zIndex: 10
    },
    loadingText: {
      marginTop: '0.5rem',
      fontSize: '0.9rem',
      color: '#4b5563'
    },
    popularityBadge: {
      position: 'absolute',
      top: '10px',
      left: '10px',
      background: '#fef3c7',
      color: '#92400e',
      padding: '3px 8px',
      borderRadius: '12px',
      fontSize: '0.7rem',
      fontWeight: '500',
      display: 'flex',
      alignItems: 'center',
      gap: '0.25rem'
    }
  };

  // Determine popularity badge
  const getPopularityBadge = () => {
    const totalResources = (course.notes || 0) + (course.pyqs || 0);
    if (totalResources > 50) return '🔥 Hot';
    if (totalResources > 30) return '⭐ Popular';
    if (totalResources > 15) return '📈 Trending';
    return null;
  };

  const popularityBadge = getPopularityBadge();

  return (
    <div style={styles.card} onClick={handleClick}>
      {/* Popularity Badge */}
      {popularityBadge && (
        <div style={styles.popularityBadge}>
          {popularityBadge}
        </div>
      )}

      {/* Course Code Badge */}
      {course.code && (
        <div style={styles.codeBadge}>
          {course.code}
        </div>
      )}

      {/* Download Progress Bar */}
      {downloading && (
        <div style={{ ...styles.downloadProgress, width: `${downloadProgress}%` }} />
      )}

      {/* Loading Overlay */}
      {downloading && (
        <div style={styles.loadingOverlay}>
          <div style={{ 
            width: '40px', 
            height: '40px', 
            border: '3px solid #e5e7eb',
            borderTop: '3px solid #4f46e5',
            borderRadius: '50%',
            animation: 'spin 1s linear infinite'
          }} />
          <div style={styles.loadingText}>
            Downloading... {downloadProgress}%
          </div>
        </div>
      )}

      <div>
        <div style={styles.cardIcon}>📚</div>
        <h3 style={styles.cardTitle}>{course.name}</h3>
        <p style={styles.cardBranch}>
          {course.branch} • Sem {course.semester}
        </p>
        
        <div style={styles.tagsContainer}>
          {course.notes > 0 && <span style={styles.tag}>📄 Notes</span>}
          {course.pyqs > 0 && <span style={styles.tag}>📝 PYQs</span>}
          <span style={styles.tag}>📋 Syllabus</span>
          {course.lab_manual && <span style={styles.tag}>🔬 Lab Manual</span>}
        </div>
      </div>
      
      <div>
        <div style={styles.stats}>
          <div style={styles.statItem}>
            <span>📄</span>
            <span>{course.notes || 0}+ notes</span>
          </div>
          <div style={styles.statItem}>
            <span>📝</span>
            <span>{course.pyqs || 0}+ PYQs</span>
          </div>
        </div>
        
        <div style={styles.actionButtons}>
          <button 
            style={styles.secondaryButton}
            onClick={handleQuickView}
            title="Quick Preview"
          >
            👁️
          </button>
          
          <button 
            style={styles.primaryButton}
            onClick={handleDownload}
            disabled={downloading}
            title="Download Materials"
          >
            {downloading ? '⏳' : '⬇️'}
            <span>Download</span>
          </button>
        </div>
      </div>

      {/* Add CSS animation */}
      <style>
        {`
          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
        `}
      </style>
    </div>
  );
};

export default CourseCard;
